for name, w in coefs.items():
    odds = np.exp(w)
    print(f"{name}: ×{odds:.2f} odds per unit")
# late_pmts: ×0.25 odds per unit (lowers approval)

import numpy as np

def log_loss(y, p, eps=1e-15):
    p = np.clip(p, eps, 1 - eps)
    return -np.mean(y * np.log(p) + (1 - y) * np.log(1 - p))

print(log_loss(np.array([1]), np.array([0.99])))  # 0.010
print(log_loss(np.array([1]), np.array([0.01])))  # 4.605
